/// <summary>
/// The class <c>ETG_SalesAgreementForm_Extension</c> is used to handle the COC methods related to <c>SalesAgreement</c> form.
/// </summary>
[ExtensionOf(formstr(SalesAgreement))]
final class ETG_SalesAgreementFormControl_Extension
{
}

Method.Source:
/// <summary>
/// Initializes the Sales Agreement form.
/// </summary>
public void init()
{
    next init();

    // Check if the current legal entity is "O001"
    if (curext() == "O001")
    {
        FormRealControl netWeightMTSControl;
        FormRealControl grossWeightMTSControl;

        // Find and adjust Net Weight control
        netWeightMTSControl = this.design().controlName("ETG_SalesAgreementHeader_NETWEIGHTMTS");
        if (netWeightMTSControl)
        {
            netWeightMTSControl.noOfDecimals(3);
        }

        // Find and adjust Gross Weight control
        grossWeightMTSControl = this.design().controlName("ETG_SalesAgreementHeader_GROSSWEIGHTMTS");
        if (grossWeightMTSControl)
        {
            grossWeightMTSControl.noOfDecimals(3);
        }
    }
}
